msg.method  = 'POST';
msg.headers = {
  'Content-Type': 'application/json',
  'x-webhook-secret': env.get('NODERED_WEBHOOK_SECRET')
};
msg.url     = env.get('APP_URL') + '/api/webhooks/nodered';
msg.payload = JSON.stringify({ action: 'refresh_statuses' });
return msg;

msg.method  = 'POST';
msg.headers = {
  'Content-Type': 'application/json',
  'x-webhook-secret': env.get('NODERED_WEBHOOK_SECRET')
};
msg.url     = env.get('APP_URL') + '/api/webhooks/nodered';
msg.payload = JSON.stringify({
  action:  'get_stats',
  user_id: env.get('FITFLOW_USER_ID')
});
return msg;

const FONNTE_TOKEN = env.get('FONNTE_TOKEN');
const INSTR_PHONE  = env.get('FITFLOW_INSTRUCTOR_PHONE');
const data = msg.payload;

if (!data || !data.ok || !data.stats) {
  node.warn('get_stats gagal: ' + JSON.stringify(data));
  return null;
}

const s = data.stats;
const rupiah = n => 'Rp ' + Number(n || 0).toLocaleString('id-ID');

const tgl = new Date().toLocaleDateString('id-ID', {
  weekday: 'long', year: 'numeric', month: 'long', day: 'numeric'
});

let sessionLines = '  (tidak ada sesi hari ini)';
if (s.sessions && s.sessions.length > 0) {
  sessionLines = s.sessions.map(ses => {
    const jam = (ses.start_time || '').slice(0, 5);
    return '  • ' + ses.class_name + (jam ? ' ' + jam : '') +
      ' - ' + (ses.attended_count || 0) + ' hadir, ' + rupiah(ses.session_revenue);
  }).join('\n');
}

const pesan =
  '📊 *Rekap Harian FitFlow*\n' +
  tgl + '\n\n' +
  '🏋️‍♀️ Sesi hari ini: *' + s.sessions_today + '*\n' +
  '👥 Total hadir: *' + s.attended_today + ' orang*\n' +
  '💰 Pendapatan: *' + rupiah(s.revenue_today) + '*\n' +
  '⏳ Menunggu konfirmasi: *' + s.pending_payments + '*\n' +
  '⚠️ Perlu Follow Up: *' + s.at_risk_members + ' member*\n\n' +
  'Detail sesi:\n' + sessionLines;

msg.method  = 'POST';
msg.headers = { 'Authorization': FONNTE_TOKEN, 'Content-Type': 'application/json' };
msg.url     = 'https://api.fonnte.com/send';
msg.payload = JSON.stringify({
  target:      INSTR_PHONE,
  message:     pesan,
  countryCode: '62'
});
return msg;

msg.method  = 'POST';
msg.headers = {
  'Content-Type': 'application/json',
  'x-webhook-secret': env.get('NODERED_WEBHOOK_SECRET')
};
msg.url     = env.get('APP_URL') + '/api/webhooks/nodered';
msg.payload = JSON.stringify({ action: 'get_pending_recipients', limit: 20 });
return msg;

const data = msg.payload;
if (!data || !data.ok || !Array.isArray(data.recipients) || data.recipients.length === 0) {
  node.status({ fill: 'grey', shape: 'ring', text: 'antrian kosong' });
  return null;
}
node.status({ fill: 'blue', shape: 'dot', text: data.recipients.length + ' pending' });
// Kirim satu msg per recipient ke wire berikutnya
return [data.recipients.map(r => ({ payload: r }))];

const FONNTE_TOKEN = env.get('FONNTE_TOKEN');
const r = msg.payload;

if (!r || !r.phone || !r.id) return null;

msg._recipient_id = r.id;

let phone = String(r.phone).replace(/\D/g, '');
if (phone.startsWith('0')) phone = '62' + phone.slice(1);

const content = (r.broadcast && r.broadcast.content)
  ? r.broadcast.content
  : '(pesan kosong)';

msg.method  = 'POST';
msg.headers = { 'Authorization': FONNTE_TOKEN, 'Content-Type': 'application/json' };
msg.url     = 'https://api.fonnte.com/send';
msg.payload = JSON.stringify({
  target:      phone,
  message:     content,
  countryCode: '62'
});
return msg;

const fonnteResp   = msg.payload;
const recipient_id = msg._recipient_id;

// Fonnte mengembalikan { status: true } jika berhasil
const ok = fonnteResp && fonnteResp.status === true;

node.status({
  fill:  ok ? 'green' : 'red',
  shape: 'dot',
  text:  ok ? 'sent: ' + recipient_id : 'failed: ' + recipient_id
});

msg.method  = 'POST';
msg.headers = {
  'Content-Type': 'application/json',
  'x-webhook-secret': env.get('NODERED_WEBHOOK_SECRET')
};
msg.url     = env.get('APP_URL') + '/api/webhooks/nodered';
msg.payload = JSON.stringify({
  action:       'mark_recipient',
  recipient_id: recipient_id,
  status:       ok ? 'sent' : 'failed'
});
return msg;

const FONNTE_TOKEN = env.get('FONNTE_TOKEN');
const INSTR_PHONE  = env.get('FITFLOW_INSTRUCTOR_PHONE');
const APP_URL      = env.get('APP_URL');

// Payload dari Supabase DB Webhook:
// { type: 'INSERT', table: 'registrations', record: { ... }, schema: 'public' }
const body   = msg.payload;
const record = (body && body.record) ? body.record : body;

if (!record || !record.registrant_name) {
  // Balas 400 ke Supabase
  msg.payload    = JSON.stringify({ ok: false, error: 'payload tidak valid' });
  msg.statusCode = 400;
  return [null, msg];
}

const rupiah = n => 'Rp ' + Number(n || 0).toLocaleString('id-ID');
const nama   = record.registrant_name  || '(tidak diketahui)';
const telp   = record.registrant_phone || '-';
const tier   = record.tier === 'early_bird' ? 'Early Bird 🔥' : 'OTS';
const jumlah = rupiah(record.amount_paid);
const bukti  = record.proof_url
  ? '\n📎 Bukti: ' + record.proof_url
  : '\n⚠️ Bukti belum diupload';

const pesan =
  '🎉 *Pendaftaran Baru!*\n\n' +
  '👤 *Nama:* ' + nama + '\n' +
  '📱 *HP:* ' + telp + '\n' +
  '🎟️ *Tier:* ' + tier + '\n' +
  '💰 *Bayar:* ' + jumlah +
  bukti + '\n\n' +
  '👉 Konfirmasi di: ' + APP_URL + '/events';

// Output 1: kirim WA ke instruktur
const waMsg = {
  method:  'POST',
  headers: { 'Authorization': FONNTE_TOKEN, 'Content-Type': 'application/json' },
  url:     'https://api.fonnte.com/send',
  payload: JSON.stringify({ target: INSTR_PHONE, message: pesan, countryCode: '62' })
};

// Output 2: balas 200 OK ke Supabase segera
msg.payload    = JSON.stringify({ ok: true });
msg.statusCode = 200;
msg.headers    = { 'Content-Type': 'application/json' };

return [waMsg, msg];

const APP_URL    = env.get('APP_URL');
const FONNTE_KEY = env.get('FONNTE_WEBHOOK_KEY');

// Teruskan body Fonnte apa adanya ke app
const originalBody = msg.payload;

msg.method  = 'POST';
msg.headers = { 'Content-Type': 'application/json' };
msg.url     = APP_URL + '/api/wa/incoming?key=' + encodeURIComponent(FONNTE_KEY);
msg.payload = JSON.stringify(originalBody);
return msg;

// Kembalikan 200 OK ke Fonnte
msg.payload    = JSON.stringify({ ok: true });
msg.statusCode = 200;
msg.headers    = { 'Content-Type': 'application/json' };
return msg;
